def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 10):
            term = ((-1)**j) * (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        if capacity < item * 1.2:
            score *= 3
            for k in range(2, 5):
                score += ((-1)**k) * (ratio ** (k+1)) / (k+1)
        elif capacity < item * 2:
            score *= 1.5
            for k in range(1, 3):
                score -= ((-1)**k) * (ratio ** (k+2)) / (k+2)
        elif capacity > item * 4:
            score /= 3
            for k in range(5, 7):
                score += ((-1)**k) * (ratio ** k) / k
        else:
            for k in range(1, 4):
                score += ((-1)**(k+1)) * (ratio ** (k*2)) / (k*2)
        if score == 0:
            priorities[i] = np.inf
        else:
            priorities[i] = -score
    return priorities
